final:
module RefModule(in1,in2, Cin, Sum,Cout);input [3:0] in1,in2;
input Cin;
output [3:0] Sum;
output Cout;

wire [3:0] obf_Pr,Ge,Carry;
assign Ge=in1&in2; 

assign obf_Pr=in1^in2;

   assign Carry[0] = Cin;
    assign Carry[1] = (Ge[0]) |(obf_Pr[0] & Carry[0]);
    assign Carry[2] = (Ge[1]) | (obf_Pr[1] & Ge[0]) | (obf_Pr[1] & obf_Pr[0] & Carry[0]);
    assign Carry[3] = (Ge[2]) | (obf_Pr[2] & Ge[1]) | (obf_Pr[2] & obf_Pr[1] & Ge[0]) |(obf_Pr[2] & obf_Pr[1] & obf_Pr[0] & Carry[0]);
    assign Cout = (Ge[3]) | (obf_Pr[3] & Ge[2]) | (obf_Pr[3] & obf_Pr[2] & Ge[1]) | 
	 (obf_Pr[3] & obf_Pr[2] & obf_Pr[1] & Ge[0]) |(obf_Pr[3] & obf_Pr[2] & obf_Pr[1] & obf_Pr[0] & Carry[0]);
    assign Sum = obf_Pr ^ Carry;endmodule
